const body = getComputedStyle(document.body);
const h1 = document.querySelector('h1');
const h1style = h1 ? getComputedStyle(h1) : null;
const btn = document.querySelector('a[href="#contact"]');
const btnStyle = btn ? getComputedStyle(btn) : null;
const nav = document.querySelector('nav') || document.querySelector('header');
const navStyle = nav ? getComputedStyle(nav) : null;
JSON.stringify({
  bodyFont: body.fontFamily,
  bodyBg: body.backgroundColor,
  bodyColor: body.color,
  h1Font: h1style && h1style.fontFamily,
  h1Size: h1style && h1style.fontSize,
  h1Weight: h1style && h1style.fontWeight,
  h1Color: h1style && h1style.color,
  btnBg: btnStyle && btnStyle.backgroundColor,
  btnColor: btnStyle && btnStyle.color,
  btnRadius: btnStyle && btnStyle.borderRadius,
  btnFont: btnStyle && btnStyle.fontFamily,
  navBg: navStyle && navStyle.backgroundColor,
}, null, 2);

function pick(el, props) {
  if (!el) return null;
  const cs = getComputedStyle(el);
  const out = {};
  props.forEach(p => out[p] = cs[p]);
  const r = el.getBoundingClientRect();
  out._width = r.width;
  return out;
}

const results = {};

// Container width
const header = document.querySelector('header') || document.querySelector('nav')?.closest('div');
results.headerHeight = header ? getComputedStyle(header).height : null;

// find a section with class containing container/wrap
const containerCandidates = [...document.querySelectorAll('div,section')].filter(el => {
  const r = el.getBoundingClientRect();
  return r.width > 900 && r.width < 1300 && el.children.length > 1;
});
results.possibleContainerWidths = [...new Set(containerCandidates.slice(0,20).map(el => Math.round(el.getBoundingClientRect().width)))];

// Buttons
const bookBtns = [...document.querySelectorAll('a')].filter(a => a.textContent.trim() === 'Book Now');
results.bookButton = pick(bookBtns[0], ['padding','fontSize','fontWeight','letterSpacing','textTransform','borderRadius','backgroundColor','color','boxShadow']);

// Badges/pills - look for small rounded elements
const pills = [...document.querySelectorAll('*')].filter(el => {
  const cs = getComputedStyle(el);
  return cs.borderRadius && parseInt(cs.borderRadius) > 15 && el.textContent.trim().length < 20 && el.textContent.trim().length > 0 && el.children.length===0;
});
results.samplePill = pick(pills[0], ['padding','fontSize','fontWeight','letterSpacing','backgroundColor','color','borderRadius']);
results.pillText = pills[0] ? pills[0].textContent.trim() : null;

// Headings
const h1 = document.querySelector('h1');
const h2 = document.querySelector('h2');
const h3 = document.querySelector('h3');
results.h1 = pick(h1, ['fontSize','fontWeight','lineHeight','letterSpacing','fontFamily']);
results.h2 = pick(h2, ['fontSize','fontWeight','lineHeight','letterSpacing','fontFamily']);
results.h3 = pick(h3, ['fontSize','fontWeight','lineHeight','letterSpacing','fontFamily']);

// Paragraph
const p = document.querySelector('p');
results.p = pick(p, ['fontSize','fontWeight','lineHeight','color','fontFamily']);

// eyebrow label (small uppercase)
const eyebrows = [...document.querySelectorAll('*')].filter(el => {
  const cs = getComputedStyle(el);
  return cs.textTransform === 'uppercase' && el.children.length === 0 && el.textContent.trim().length > 3 && el.textContent.trim().length < 60;
});
results.eyebrow = pick(eyebrows[0], ['fontSize','fontWeight','letterSpacing','color']);
results.eyebrowText = eyebrows[0]?.textContent.trim();

// dark section bg
const darkSections = [...document.querySelectorAll('section,div')].filter(el => {
  const bg = getComputedStyle(el).backgroundColor;
  return bg === 'rgb(16, 44, 71)' || bg.startsWith('rgb(1') ;
});
const darkBgs = [...new Set([...document.querySelectorAll('*')].map(el=>getComputedStyle(el).backgroundColor))].filter(c => c !== 'rgba(0, 0, 0, 0)' && c!== 'rgb(255, 255, 255)');
results.uniqueBackgroundColors = darkBgs.slice(0,25);

// border radius values used on cards
const radii = [...new Set([...document.querySelectorAll('*')].map(el=>getComputedStyle(el).borderRadius))].filter(r=>r && r!=='0px');
results.uniqueBorderRadii = radii.slice(0,20);

// box shadows
const shadows = [...new Set([...document.querySelectorAll('*')].map(el=>getComputedStyle(el).boxShadow))].filter(s=>s && s!=='none');
results.uniqueShadows = shadows.slice(0,10);

// viewport / breakpoint check
results.viewportWidth = window.innerWidth;

JSON.stringify(results, null, 2);

function pick(el, props) {
  if (!el) return null;
  const cs = getComputedStyle(el);
  const out = {};
  props.forEach(p => out[p] = cs[p]);
  return out;
}
const h2 = document.querySelector('h2');
const h3 = document.querySelector('h3');
const p = document.querySelector('p');
const eyebrows = [...document.querySelectorAll('*')].filter(el => {
  const cs = getComputedStyle(el);
  return cs.textTransform === 'uppercase' && el.children.length === 0 && el.textContent.trim().length > 3 && el.textContent.trim().length < 60;
});
const out = {
  h2: pick(h2, ['fontSize','fontWeight','lineHeight','letterSpacing']),
  h3: pick(h3, ['fontSize','fontWeight','lineHeight','letterSpacing']),
  p: pick(p, ['fontSize','fontWeight','lineHeight','color']),
  eyebrow: pick(eyebrows[0], ['fontSize','fontWeight','letterSpacing','color']),
  eyebrowText: eyebrows[0]?.textContent.trim(),
};
JSON.stringify(out, null, 2);

