    "h3": { "fontSize": "clamp(1.25rem, 2vw, 1.75rem)", "fontWeight": 700, "lineHeight": 1.2, "letterSpacing": "-0.01em" },
    "body": { "fontSize": "1.05rem", "fontWeight": 400, "lineHeight": 1.7, "letterSpacing": "normal" },
    "eyebrow": { "fontSize": "0.62rem", "fontWeight": 600, "lineHeight": 1.4, "letterSpacing": "0.14em", "textTransform": "uppercase" },
    "button": { "fontSize": "0.8125rem", "fontWeight": 700, "letterSpacing": "normal" }
  },
  "radius": {
    "xs": "2px",
    "sm": "6px",
    "md": "12px",
    "lg": "14px",
    "xl": "24px",
    "pill": "999px",
    "circle": "50%"
  },
  "shadow": {
    "card": "0 8px 32px rgba(12,28,63,0.16)",
    "pill": "0 4px 18px rgba(12,40,63,0.3)",
    "deep": "0 -4px 24px rgba(0,0,0,0.22)"
  },
  "layout": {
    "containerWide": "1180px",
    "containerNarrow": "1000px",
    "sectionPaddingY": { "desktop": "140px", "mobile": "64px" },
    "gridServices": { "columns": 3, "rows": 2 },
    "gridStats": { "columns": 4 },
    "gridProcess": { "columns": 4 }
  },
  "components": {
    "buttonPrimary": {
      "background": "#101416",
      "color": "#FFFFFF",
      "padding": "10px 24px",
      "borderRadius": "999px",
      "fontWeight": 700,
      "fontSize": "13px",
      "border": "none",
      "hoverShadow": "0 4px 18px rgba(12,40,63,0.3)"
    },
    "badgePale": {
      "background": "#E8F4FB",
      "color": "#0C283F",
      "padding": "6px 14px",
      "borderRadius": "999px",
      "fontWeight": 600,
      "fontSize": "0.72rem"
    },
    "badgeOnDark": {
      "background": "rgba(255,255,255,0.05)",
      "color": "#FFFFFF",
      "padding": "6px 14px",
      "borderRadius": "999px",
      "fontWeight": 600,
      "fontSize": "0.72rem"
    },
    "cardLight": {
      "background": "#F0EDE8",
      "borderRadius": "12px",
      "padding": "32px",
      "border": "none"
    },
    "cardDark": {
      "background": "#0F1A2A",
      "borderRadius": "12px",
      "padding": "32px",
      "borderLeft": "4px solid rgba(255,255,255,0.2)"
    },
    "navBar": {
      "background": "rgba(248,247,244,0.93)",
      "backdropBlur": "12px",
      "position": "sticky",
      "borderBottom": "1px solid rgba(16,20,22,0.08)"
    },
    "footer": {
      "background": "#0F1A2A",
      "color": "#FFFFFF",
      "columns": 3
    }
  },
  "motifs": [
    "Numbered labels (01, 02, 03...) reused across services, findings, and process steps as a connective visual thread",
    "Alternating light (cream) and dark (navy) full-bleed section backgrounds for vertical rhythm",
    "Pill shape (border-radius 999px) applied consistently to buttons and badges",
    "One italic accent word/phrase per major headline for emotional emphasis, same font family",
    "Minimal color palette (3 neutrals + 1 navy) — visual interest comes from type scale and weight contrast, not color variety"
  ]
}

